describe('AuthController', () => {
  let controller: AuthController;
  let authService: AuthService;

  beforeEach(async () => {
    const mockAuthService = {
      validateUser: jest.fn(),
      login: jest.fn().mockResolvedValue({ access_token: 'fake-jwt' }),
    };

    const module = await Test.createTestingModule({
      controllers: [AuthController],
      providers: [{ provide: AuthService, useValue: mockAuthService }],
    }).compile();

    controller = module.get<AuthController>(AuthController);
    authService = module.get<AuthService>(AuthService);
  });

  it('doit retourner 200 et un token si identifiants valides', async () => {
    const dto = { email: 'test@test.com', password: '123456' };
    authService.validateUser.mockResolvedValue({ id: 1, email: dto.email });

    const result = await controller.login(dto);
    expect(result).toEqual({ access_token: 'fake-jwt' });
    expect(authService.validateUser).toHaveBeenCalledWith(dto.email, dto.password);
  });

  it('doit lever une exception 401 si identifiants invalides', async () => {
    const dto = { email: 'wrong@test.com', password: 'wrong' };
    authService.validateUser.mockResolvedValue(null);

    await expect(controller.login(dto)).rejects.toThrow(UnauthorizedException);
  });
});
